SELECT DISTINCT year, grande_regiao, estado, produto, vendas FROM (SELECT TRY_CAST(trim("ano") AS INTEGER) AS year, NULLIF(TRIM("grande_regiao"), '') AS grande_regiao, NULLIF(TRIM("estado"), '') AS estado, NULLIF(TRIM("produto"), '') AS produto, TRY_CAST(replace(replace(trim("vendas"), '.', ''), ',', '.') AS DOUBLE) AS vendas FROM "anp-brazil-arquivos-vendas-anuais-de-etanol-hidratado-e-derivados-de-petroleo-por-estado-ve") WHERE year IS NOT NULL AND (vendas IS NOT NULL)
